{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOCxlu9cjeTPazTggbNhent"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"bxMaNzIm9eIV"},"outputs":[],"source":["\"\"\"\n","analyze_predictions.py\n","\n","Run YOLO inference over a set of image folders and generate a per-image\n","summary table containing detection counts and average confidence scores.\n","\"\"\"\n","\n","from __future__ import annotations\n","\n","import gc\n","import math\n","from pathlib import Path\n","\n","import numpy as np\n","import pandas as pd\n","import torch\n","from ultralytics import YOLO\n","\n","from config import MODEL_PATH, TRAIN_DIR, VAL_DIR\n","\n","IMAGE_EXTENSIONS = (\"*.jpg\", \"*.jpeg\", \"*.png\", \"*.tif\", \"*.tiff\", \"*.bmp\", \"*.webp\")\n","\n","DEVICE = \"cpu\"       # Use \"cpu\", \"cuda\", or 0 for first GPU\n","CHUNK_SIZE = 25\n","IMGSZ = 416\n","CONF = 0.25\n","OUTPUT_CSV = \"prediction_summary.csv\"\n","\n","\n","def collect_image_paths(*folders: Path) -> list[Path]:\n","    \"\"\"Collect image paths from one or more directories.\"\"\"\n","    image_paths: list[Path] = []\n","    for folder in folders:\n","        for pattern in IMAGE_EXTENSIONS:\n","            image_paths.extend(folder.glob(pattern))\n","    return sorted(image_paths)\n","\n","\n","def summarize_prediction(result) -> tuple[int, float]:\n","    \"\"\"\n","    Extract detection count and average confidence from a YOLO result.\n","\n","    Returns:\n","        detected_count: Number of predicted boxes\n","        avg_confidence: Mean confidence across predicted boxes, or NaN if none\n","    \"\"\"\n","    if result.boxes is not None and len(result.boxes) > 0:\n","        confidences = result.boxes.conf.detach().cpu().numpy()\n","        detected_count = len(confidences)\n","        avg_confidence = float(np.mean(confidences))\n","    else:\n","        detected_count = 0\n","        avg_confidence = np.nan\n","\n","    return detected_count, avg_confidence\n","\n","\n","def run_inference_summary(\n","    model: YOLO,\n","    image_paths: list[Path],\n","    chunk_size: int = CHUNK_SIZE,\n","    imgsz: int = IMGSZ,\n","    conf: float = CONF,\n","    device: str | int = DEVICE,\n",") -> pd.DataFrame:\n","    \"\"\"Run chunked YOLO inference and return a per-image summary table.\"\"\"\n","    rows: list[dict] = []\n","    num_chunks = math.ceil(len(image_paths) / chunk_size)\n","\n","    for i in range(num_chunks):\n","        chunk = image_paths[i * chunk_size : (i + 1) * chunk_size]\n","        print(f\"Processing chunk {i + 1}/{num_chunks} ({len(chunk)} images)\")\n","\n","        results = model.predict(\n","            source=[str(path) for path in chunk],\n","            conf=conf,\n","            imgsz=imgsz,\n","            batch=1,\n","            stream=True,\n","            device=device,\n","            save=False,\n","            verbose=False,\n","        )\n","\n","        for image_path, result in zip(chunk, results):\n","            detected_count, avg_confidence = summarize_prediction(result)\n","\n","            rows.append(\n","                {\n","                    \"image_name\": image_path.name,\n","                    \"image_path\": str(image_path),\n","                    \"detected_count\": detected_count,\n","                    \"avg_confidence\": round(avg_confidence, 4) if not np.isnan(avg_confidence) else np.nan,\n","                }\n","            )\n","\n","        del results\n","        gc.collect()\n","        if torch.cuda.is_available():\n","            torch.cuda.empty_cache()\n","\n","    return pd.DataFrame(rows)\n","\n","\n","def add_totals_row(df: pd.DataFrame) -> pd.DataFrame:\n","    \"\"\"Append a totals row to the prediction summary table.\"\"\"\n","    mean_conf = (\n","        float(df.loc[df[\"detected_count\"] > 0, \"avg_confidence\"].mean())\n","        if (df[\"detected_count\"] > 0).any()\n","        else np.nan\n","    )\n","\n","    totals_row = pd.DataFrame(\n","        [\n","            {\n","                \"image_name\": \"TOTAL\",\n","                \"image_path\": \"\",\n","                \"detected_count\": int(df[\"detected_count\"].sum()),\n","                \"avg_confidence\": round(mean_conf, 4) if not np.isnan(mean_conf) else np.nan,\n","            }\n","        ]\n","    )\n","\n","    return pd.concat([df, totals_row], ignore_index=True)\n","\n","\n","def main() -> None:\n","    \"\"\"Run YOLO prediction summary generation.\"\"\"\n","    image_paths = collect_image_paths(TRAIN_DIR, VAL_DIR)\n","\n","    print(f\"Total images found: {len(image_paths)}\")\n","    print(\"First few images:\", image_paths[:5])\n","\n","    if not image_paths:\n","        raise FileNotFoundError(\"No image files found in the specified train/val folders.\")\n","\n","    model = YOLO(str(MODEL_PATH))\n","    df = run_inference_summary(model, image_paths)\n","    df_final = add_totals_row(df)\n","\n","    output_path = Path(OUTPUT_CSV)\n","    df_final.to_csv(output_path, index=False)\n","\n","    print(f\"Saved prediction summary to: {output_path.resolve()}\")\n","    print(df_final.head())\n","\n","\n","if __name__ == \"__main__\":\n","    main()"]}]}